(window.webpackJsonp=window.webpackJsonp||[]).push([[594],{579:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">grid</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxDistance = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">grid</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> N=grid.length\\n  <span class=\\"hljs-keyword\\">let</span> aux=<span class=\\"hljs-built_in\\">Array</span>(N).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span><span class=\\"hljs-built_in\\">Array</span>(N).fill(<span class=\\"hljs-literal\\">Infinity</span>))\\n  <span class=\\"hljs-keyword\\">let</span> used=<span class=\\"hljs-built_in\\">Array</span>(N).fill().map(<span class=\\"hljs-function\\"><span class=\\"hljs-params\\">()</span>=&gt;</span><span class=\\"hljs-built_in\\">Array</span>(N).fill(<span class=\\"hljs-literal\\">false</span>))\\n  <span class=\\"hljs-keyword\\">let</span> moves=[[<span class=\\"hljs-number\\">-1</span>,<span class=\\"hljs-number\\">0</span>],[<span class=\\"hljs-number\\">1</span>,<span class=\\"hljs-number\\">0</span>],[<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">1</span>],[<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">-1</span>]]\\n  <span class=\\"hljs-keyword\\">let</span> arr=[]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;N;i++){\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;N;j++){\\n      <span class=\\"hljs-keyword\\">if</span>(grid[i][j]===<span class=\\"hljs-number\\">1</span>){\\n        arr.push([i,j])\\n        aux[i][j]=<span class=\\"hljs-number\\">0</span>\\n      }\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">if</span>(arr.length===<span class=\\"hljs-number\\">0</span> || arr.length===N*N)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-keyword\\">while</span>(arr.length&gt;<span class=\\"hljs-number\\">0</span>){\\n    <span class=\\"hljs-comment\\">// console.log(arr)</span>\\n    <span class=\\"hljs-keyword\\">let</span> len=arr.length\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;len;i++){\\n      <span class=\\"hljs-keyword\\">let</span> [x,y]=arr.shift()\\n      used[x][y]=<span class=\\"hljs-literal\\">true</span>\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [dx,dy] <span class=\\"hljs-keyword\\">of</span> moves){\\n        <span class=\\"hljs-keyword\\">let</span> nx=x+dx\\n        <span class=\\"hljs-keyword\\">let</span> ny=y+dy\\n        <span class=\\"hljs-keyword\\">if</span>(nx&lt;<span class=\\"hljs-number\\">0</span> || nx&gt;=N || ny&lt;<span class=\\"hljs-number\\">0</span> || ny&gt;=N)<span class=\\"hljs-keyword\\">continue</span>\\n        <span class=\\"hljs-keyword\\">if</span>(used[nx][ny])<span class=\\"hljs-keyword\\">continue</span>\\n        used[nx][ny]=<span class=\\"hljs-literal\\">true</span>\\n        <span class=\\"hljs-keyword\\">if</span>(grid[nx][ny]===<span class=\\"hljs-number\\">1</span>)<span class=\\"hljs-keyword\\">continue</span>\\n        aux[nx][ny]=<span class=\\"hljs-built_in\\">Math</span>.min(aux[nx][ny],aux[x][y]+<span class=\\"hljs-number\\">1</span>)\\n        arr.push([nx,ny])\\n      }\\n    }\\n  }\\n  <span class=\\"hljs-comment\\">// console.log(aux)</span>\\n  <span class=\\"hljs-keyword\\">let</span> res=-<span class=\\"hljs-literal\\">Infinity</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;N;i++){\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;N;j++){\\n      <span class=\\"hljs-keyword\\">if</span>(aux[i][j]===<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">continue</span>\\n      res=<span class=\\"hljs-built_in\\">Math</span>.max(res,aux[i][j])\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"as-far-from-land-as-possible","hasThinking":false,"content":"<p>\u4f60\u73b0\u5728\u624b\u91cc\u6709\u4e00\u4efd\u5927\u5c0f\u4e3a&nbsp;N x N \u7684 \u7f51\u683c <code>grid</code>\uff0c\u4e0a\u9762\u7684\u6bcf\u4e2a \u5355\u5143\u683c \u90fd\u7528&nbsp;<code>0</code>&nbsp;\u548c&nbsp;<code>1</code>&nbsp;\u6807\u8bb0\u597d\u4e86\u3002\u5176\u4e2d&nbsp;<code>0</code>&nbsp;\u4ee3\u8868\u6d77\u6d0b\uff0c<code>1</code>&nbsp;\u4ee3\u8868\u9646\u5730\uff0c\u8bf7\u4f60\u627e\u51fa\u4e00\u4e2a\u6d77\u6d0b\u5355\u5143\u683c\uff0c\u8fd9\u4e2a\u6d77\u6d0b\u5355\u5143\u683c\u5230\u79bb\u5b83\u6700\u8fd1\u7684\u9646\u5730\u5355\u5143\u683c\u7684\u8ddd\u79bb\u662f\u6700\u5927\u7684\u3002</p>\\n\\n<p>\u6211\u4eec\u8fd9\u91cc\u8bf4\u7684\u8ddd\u79bb\u662f\u300c\u66fc\u54c8\u987f\u8ddd\u79bb\u300d\uff08&nbsp;Manhattan Distance\uff09\uff1a<code>(x0, y0)</code> \u548c&nbsp;<code>(x1, y1)</code>&nbsp;\u8fd9\u4e24\u4e2a\u5355\u5143\u683c\u4e4b\u95f4\u7684\u8ddd\u79bb\u662f&nbsp;<code>|x0 - x1| + |y0 - y1|</code>&nbsp;\u3002</p>\\n\\n<p>\u5982\u679c\u7f51\u683c\u4e0a\u53ea\u6709\u9646\u5730\u6216\u8005\u6d77\u6d0b\uff0c\u8bf7\u8fd4\u56de&nbsp;<code>-1</code>\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/08/17/1336_ex1.jpeg\\" style=\\"height: 87px; width: 185px;\\"></strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>[[1,0,1],[0,0,0],[1,0,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>2\\n<strong>\u89e3\u91ca\uff1a </strong>\\n\u6d77\u6d0b\u5355\u5143\u683c (1, 1) \u548c\u6240\u6709\u9646\u5730\u5355\u5143\u683c\u4e4b\u95f4\u7684\u8ddd\u79bb\u90fd\u8fbe\u5230\u6700\u5927\uff0c\u6700\u5927\u8ddd\u79bb\u4e3a 2\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/08/17/1336_ex2.jpeg\\" style=\\"height: 87px; width: 184px;\\"></strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>[[1,0,0],[0,0,0],[0,0,0]]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n<strong>\u89e3\u91ca\uff1a </strong>\\n\u6d77\u6d0b\u5355\u5143\u683c (2, 2) \u548c\u6240\u6709\u9646\u5730\u5355\u5143\u683c\u4e4b\u95f4\u7684\u8ddd\u79bb\u90fd\u8fbe\u5230\u6700\u5927\uff0c\u6700\u5927\u8ddd\u79bb\u4e3a 4\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ol>\\n\\t<li><code>1 &lt;= grid.length == grid[0].length&nbsp;&lt;= 100</code></li>\\n\\t<li><code>grid[i][j]</code>&nbsp;\u4e0d\u662f&nbsp;<code>0</code>&nbsp;\u5c31\u662f&nbsp;<code>1</code></li>\\n</ol>\\n","title":"1162. \u5730\u56fe\u5206\u6790","relatedTags":["\u5e7f\u5ea6\u4f18\u5148\u641c\u7d22","\u56fe"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1162"}')}}]);